@startuml
skinparam classAttributeIconSize 0

class ASTNode <<abstract>> {
  getLine(): int
  getColumn(): int
}

class Type <<abstract>>

class IntType
class RealType
class CharType
class VoidType

class ArrayType {
  size: int
  type: Type
}

class FunctionType {
  params: List<VarDef>
  returnType: Type
}

class StructType {
  fields: List<StructField>
}

class StructField {
  name: String
  type: Type
}

Type --|> ASTNode

IntType ..|> Type
RealType ..|> Type
CharType ..|> Type
ArrayType ..|> Type
VoidType ..|> Type
FunctionType ..|> Type
StructType ..|> Type

StructType o-- StructField
StructField --|> ASTNode
@enduml
